SELECT MAX(ms) AS max_magnetic_susceptibility
FROM specimens
WHERE year = 2023;

SELECT AVG(ms) AS average_magnetic_susceptibility
FROM specimens
WHERE site_id = 1;

SELECT specimen_name
FROM specimens
WHERE collector_name = 'Dr. Jane Smith' AND year = 2005;

SELECT specimen_name
FROM specimens
ORDER BY specimen_name ASC;

SELECT specimen_id
FROM data_quality
WHERE quality_score = (
    SELECT MAX(quality_score) 
    FROM data_quality
);

SELECT specimen_id, ms AS magnetic_susceptibility
FROM specimens
ORDER BY magnetic_susceptibility DESC;
